class Solution:
    def minSwaps(self, s):
        # Repeatedly remove matched [] pairs by stack, then count leftover ][ structure.
        stack = []
        for ch in s:
            if ch == '[':
                stack.append(ch)
            else:
                if stack and stack[-1] == '[':
                    stack.pop()
                else:
                    stack.append(ch)
        # leftover is ]]]...[[[ ; number of ']' (== number of '[') is unmatched closers
        closers = stack.count(']')
        return (closers + 1) // 2

