class Solution:
    def minSwaps(self, s):
        bal = 0
        worst = 0
        for ch in s:
            if ch == '[':
                bal += 1
            else:
                bal -= 1
                if bal < worst:
                    worst = bal
        deficit = -worst
        return (deficit + 1) // 2

