var minSwaps = function(s) {
    let bal = 0, worst = 0;
    for (const ch of s) {
        if (ch === '[') bal++;
        else {
            bal--;
            if (bal < worst) worst = bal;
        }
    }
    const deficit = -worst;
    return Math.floor((deficit + 1) / 2);
};
